// Validate incoming payload. FastAPI sends:
//   {
//     orderNumber, ebayNet, lines: [{date, type, net, description}],
//     parentSoId?       // present for NO_LINKED_INVOICES (existing SO, no invoice yet)
//     defaultSocid?     // present for MISSING_IN_DOLIBARR (no SO at all)
//   }
const body = items[0].json.body || items[0].json;
if (!body.orderNumber) throw new Error('orderNumber is required');
if (!Array.isArray(body.lines) || body.lines.length === 0) throw new Error('lines[] is required and non-empty');
if (!body.parentSoId && !body.defaultSocid) {
  throw new Error('Need either parentSoId (NO_LINKED_INVOICES) or defaultSocid (MISSING_IN_DOLIBARR)');
}

const mode = body.parentSoId ? 'from_so' : 'standalone';

return [{ json: {
  mode,
  orderNumber:   String(body.orderNumber),
  ebayNet:       Number(body.ebayNet || 0),
  lines:         body.lines,
  parentSoId:    body.parentSoId ? String(body.parentSoId) : null,
  defaultSocid:  body.defaultSocid ? String(body.defaultSocid) : null,
  label:         body.label || `eBay reconciliation - ${body.orderNumber}`,
}}];

// Combine validated input with the parent SO (if any) and build the Dolibarr
// POST body. Lines come from the eBay CSV breakdown so the new invoice mirrors
// the per-row eBay activity.
const input = $('Validate input').first().json;
const hasSO = input.mode === 'from_so';
const so = hasSO ? items[0].json : null;
if (hasSO && (!so || !so.socid)) {
  throw new Error('Parent SO ' + input.parentSoId + ' could not be fetched or has no socid');
}
const socid = hasSO ? so.socid : input.defaultSocid;
const nowUnix = Math.floor(Date.now() / 1000);

const payload = {
  socid,
  type: 0,  // regular invoice; negative lines reduce total - Dolibarr handles mixed-sign lines
  ref_client: input.orderNumber,
  date: nowUnix,
  note_private: `Auto-created via eBay reconciliation. eBay order: ${input.orderNumber}.${hasSO ? ` Linked to SO ${so.ref} (id ${so.id}).` : ' No SO existed; using default eBay customer.'}`,
  lines: input.lines.map(l => ({
    desc: `[${l.type || 'eBay'}] ${l.description || ''} (${l.date || ''})`.replace(/\s+\(\)/, '').trim(),
    qty: 1,
    subprice: Number(l.net || 0),
    tva_tx: 0,
  })),
};

if (hasSO) {
  payload.fk_facture_source = null;
  payload.origin_type = 'commande';
  payload.origin_id   = Number(input.parentSoId);
}

return [{ json: {
  _input: input,
  _so: hasSO ? { id: so.id, ref: so.ref, socid: so.socid } : null,
  _socid: String(socid),
  _payload: payload,
}}];

// Parse create-invoice response; Dolibarr returns the new id as a bare integer
// or {error: ...}. Stash newInvoiceId for the validate step.
const raw = items[0].json;
const prior = $('Build Dolibarr payload').first().json;
const input = prior._input;

let newId = null;
if (typeof raw === 'number') newId = raw;
else if (typeof raw === 'string' && /^\d+$/.test(raw)) newId = Number(raw);
else if (raw && typeof raw === 'object' && raw.id) newId = raw.id;

if (!newId) {
  const msg = (raw && raw.error && (raw.error.message || raw.error['0'])) || JSON.stringify(raw).slice(0, 400);
  throw new Error('Create invoice failed: ' + msg);
}

return [{ json: { ...prior, newInvoiceId: String(newId), _input: input } }];

// Final shape: surface the new invoice ref, link, and bookkeeping context.
const raw = items[0].json;
const prior = $('Parse create response').first().json;
const input = prior._input;
const newId = prior.newInvoiceId;
const so = prior._so;
const socid = prior._socid;

if (raw && raw.error) {
  throw new Error('Validate failed: ' + (raw.error.message || JSON.stringify(raw.error)));
}
const validatedRef = (raw && raw.ref) ? raw.ref : null;
const totalHt = raw && raw.total_ht != null ? Number(raw.total_ht) : null;

return [{ json: {
  ok: true,
  mode: input.mode,
  orderNumber: input.orderNumber,
  newInvoiceId: newId,
  newInvoiceRef: validatedRef,
  totalHt,
  socid,
  so,
  validated: true,
  dolibarrEditUrl: `https://staging.txscorp.com/compta/facture/card.php?id=${newId}`,
  message: input.mode === 'from_so'
    ? `Created and validated invoice ${validatedRef} for ${(totalHt||0).toFixed(2)}, linked to SO ${so ? so.ref : ''}.`
    : `Created and validated invoice ${validatedRef} for ${(totalHt||0).toFixed(2)} under customer ${socid} (no SO).`,
}}];
